phase1.code:
import java.io.*;

public class PrintWriterExample {
    public static void main(String[] args) {
        // PrintWriter for formatted output
        System.out.println("=== PrintWriter Basics ===");
        try (PrintWriter pw = new PrintWriter(new FileWriter("output.txt"))) {
            pw.println("Hello, World!");
            pw.println("PrintWriter is awesome!");
            pw.printf("Number: %d, Decimal: %.2f, String: %s%n", 42, 3.14159, "Java");
            pw.println("Done!");
            System.out.println("File written!");
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        }

        // PrintWriter with autoflush
        System.out.println("=== Autoflush ===");
        try (PrintWriter pw = new PrintWriter(new FileWriter("autoflush.txt"), true)) {
            // true = autoflush on println/printf
            pw.println("This line is flushed immediately!");
            pw.println("Autoflush is useful for real-time output");
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        }

        // System.out is a PrintStream (similar to PrintWriter)
        System.out.println("=== System.out ===");
        System.out.print("Print without newline ");
        System.out.println("Print with newline");
        System.out.printf("Formatted: %d, %f, %s%n", 10, 20.5, "Hello");

        // Console input with BufferedReader
        System.out.println("=== Console Input ===");
        try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in))) {
            System.out.print("Enter your name: ");
            String name = reader.readLine();
            System.out.print("Enter your age: ");
            String ageStr = reader.readLine();
            int age = Integer.parseInt(ageStr);

            System.out.println("Name: " + name);
            System.out.println("Age: " + age);
        } catch (IOException e) {
            System.out.println("Input error: " + e.getMessage());
        } catch (NumberFormatException e) {
            System.out.println("Invalid number format!");
        }

        // Formatting with System.out.printf
        System.out.println("=== Formatting ===");
        System.out.printf("Integer: %d%n", 42);
        System.out.printf("Float: %.2f%n", 3.14159);
        System.out.printf("String: %s%n", "Java");
        System.out.printf("Hex: %x%n", 255);
        System.out.printf("Oct: %o%n", 8);
        System.out.printf("Scientific: %e%n", 12345.6789);

        // Formatted table
        System.out.println("=== Table ===");
        System.out.printf("%-10s %-10s %-10s%n", "Name", "Age", "Grade");
        System.out.printf("%-10s %-10d %-10.2f%n", "Alice", 20, 3.75);
        System.out.printf("%-10s %-10d %-10.2f%n", "Bob", 22, 3.20);
        System.out.printf("%-10s %-10d %-10.2f%n", "Charlie", 19, 3.95);
    }
}

