import java.io.*;

public class Test {
    public static void main(String[] args) {
        try (PrintWriter pw = new PrintWriter("file.txt")) {
            // Missing throws/close declaration
            pw.println("Hello");
        }

        // Using pw after try-with-resources
        pw.println("World!");  // ERROR!
    }
}

phase2.explanation:
pw is declared inside the try-with-resources block, so it's only accessible INSIDE the try block!

FIX: Keep all PrintWriter operations inside the try block:

try (PrintWriter pw = new PrintWriter("file.txt")) {
    pw.println("Hello");
    pw.println("World!");  // Move inside try
} // pw is automatically closed here

Remember: Resources declared in try-with-resources are only valid within the try block!

phase3.solution:
import java.io.*;

public class PrintWriterPractice {
    public static void main(String[] args) {
        // Write
        try (PrintWriter pw = new PrintWriter(new FileWriter("grades.txt"))) {
            pw.printf("%-10s %s%n", "Name", "Grade");
            pw.printf("%-10s %s%n", "Alice", "A");
            pw.printf("%-10s %s%n", "Bob", "B+");
            pw.printf("%-10s %s%n", "Charlie", "A-");
            System.out.println("File written!");
        } catch (IOException e) {
            System.out.println("Error writing: " + e.getMessage());
        }

        // Read
        try (BufferedReader br = new BufferedReader(new FileReader("grades.txt"))) {
            String line;
            System.out.println("Reading grades:");
            while ((line = br.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            System.out.println("Error reading: " + e.getMessage());
        }
    }
}
